import React, { useState, useEffect } from 'react';
import FloatingUserCard from './FloatingUserCard';

const LiveNotifications = ({ usersData, onUserClick }) => {
  const [notifications, setNotifications] = useState([
    {
      id: 1,
      user: {
        name: "Ana Silva",
        avatar: "https://images.pexels.com/photos/1239291/pexels-photo-1239291.jpeg?auto=compress&cs=tinysrgb&w=100&h=100&fit=crop",
        status: "online"
      },
      activity: "Analyzing sales data",
      timestamp: Date.now() - 300000 // 5 min ago
    },
    {
      id: 2,
      user: {
        name: "Carlos Santos",
        avatar: "https://images.pexels.com/photos/2379004/pexels-photo-2379004.jpeg?auto=compress&cs=tinysrgb&w=100&h=100&fit=crop",
        status: "online"
      },
      activity: "Reviewing code for bug fixes",
      timestamp: Date.now() - 600000 // 10 min ago
    },
    {
      id: 3,
      user: {
        name: "Maria Costa",
        avatar: "https://images.pexels.com/photos/774909/pexels-photo-774909.jpeg?auto=compress&cs=tinysrgb&w=100&h=100&fit=crop",
        status: "online"
      },
      activity: "Finalizing client proposal draft",
      timestamp: Date.now() - 900000 // 15 min ago
    },
    {
      id: 4,
      user: {
        name: "João Oliveira",
        avatar: "https://images.pexels.com/photos/1222271/pexels-photo-1222271.jpeg?auto=compress&cs=tinysrgb&w=100&h=100&fit=crop",
        status: "away"
      },
      activity: "Keeping up with industry trends",
      timestamp: Date.now() - 1200000 // 20 min ago
    },
    {
      id: 5,
      user: {
        name: "Fernanda Lima",
        avatar: "https://images.pexels.com/photos/1181686/pexels-photo-1181686.jpeg?auto=compress&cs=tinysrgb&w=100&h=100&fit=crop",
        status: "online"
      },
      activity: "Working on data analysis",
      timestamp: Date.now() - 1500000 // 25 min ago
    },
    {
      id: 6,
      user: {
        name: "Pedro Alves",
        avatar: "https://images.pexels.com/photos/1043471/pexels-photo-1043471.jpeg?auto=compress&cs=tinysrgb&w=100&h=100&fit=crop",
        status: "online"
      },
      activity: "Deploying new features",
      timestamp: Date.now() - 1800000 // 30 min ago
    }
  ]);

  // Simular atualizações em tempo real
  useEffect(() => {
    const interval = setInterval(() => {
      setNotifications(prev => {
        const updated = [...prev];
        // Atualizar timestamp aleatoriamente
        const randomIndex = Math.floor(Math.random() * updated.length);
        updated[randomIndex] = {
          ...updated[randomIndex],
          timestamp: Date.now()
        };
        return updated.sort((a, b) => b.timestamp - a.timestamp);
      });
    }, 10000); // Atualizar a cada 10 segundos

    return () => clearInterval(interval);
  }, []);

  const getStatusColor = (status) => {
    switch (status) {
      case 'online': return 'bg-green-500';
      case 'away': return 'bg-orange-500';
      case 'busy': return 'bg-red-500';
      default: return 'bg-gray-500';
    }
  };

  return (
    <div className="flex-1 bg-neutral-800 rounded-lg h-20 p-4 relative overflow-hidden">
      {/* Notifications Container */}
      <div className="flex space-x-3 overflow-hidden relative h-full items-center">
        {notifications.map((notification, index) => (
          <div
            key={notification.id}
            className="flex items-center space-x-3 flex-shrink-0 min-w-0 border border-neutral-700 p-2 rounded-md"
            style={{
              opacity: index > 4 ? 0.3 : 1,
              transform: index > 4 ? 'scale(0.9)' : 'scale(1)'
            }}
          >
            {/* Avatar with Status */}
            <div className="relative flex-shrink-0">
              <img
                src={notification.user.avatar}
                alt={notification.user.name}
                className="w-5 h-5 rounded-lg"
              />
              <div className={`absolute -bottom-0.5 -right-0.5 w-2 h-2 rounded-full border border-neutral-800 ${getStatusColor(notification.user.status)}`} />
            </div>

            {/* Activity Description */}
            <div className="min-w-0 flex-1">
              <p className="text-white text-xs font-normal truncate max-w-32">
                {notification.activity}
              </p>
            </div>
          </div>
        ))}

        {/* Fade Out Gradient */}
        <div className="absolute right-0 top-0 bottom-0 w-8 bg-gradient-to-l from-neutral-800 to-transparent pointer-events-none" />
      </div>
    </div>
  );
};

export default LiveNotifications;
